from __future__ import annotations

"""Baseline TinyStories adapter using the standard torch.export path."""

import torch
from transformers import AutoModelForCausalLM


EXPORT_STRICT = False


def build_model(model_path: str | None) -> torch.nn.Module:
    if model_path is None:
        raise RuntimeError("TinyStories adapter requires --model-path")
    return AutoModelForCausalLM.from_pretrained(
        model_path,
        use_cache=False,
        attn_implementation="eager",
        local_files_only=True,
    ).eval()


def example_inputs() -> tuple[torch.Tensor, ...]:
    return (torch.zeros((1, 1), dtype=torch.long),)

from __future__ import annotations

import torch

from sim_utils import load_matmul_module


MatmulModule = load_matmul_module()


def build_model(_model_path: str | None) -> torch.nn.Module:
    return MatmulModule().eval()


def example_inputs() -> tuple[torch.Tensor, ...]:
    return (
        torch.zeros((16,), dtype=torch.int32),
        torch.zeros((16,), dtype=torch.int32),
    )

import torch

class MatmulModule(torch.nn.Module):
    def forward(self, a, b):
        return torch.matmul(a, b)

